
import { Users, UserPlus } from "lucide-react";

export default function MembersPage() {
    const members = [
        { id: 1, name: "Maria García", role: "Fallera Mayor", status: "Activo", email: "maria.garcia@example.com" },
        { id: 2, name: "Jose Martínez", role: "Presidente", status: "Activo", email: "jose.martinez@example.com" },
        { id: 3, name: "Lucía Sanchis", role: "Fallero", status: "Pendiente", email: "lucia.sanchis@example.com" },
        { id: 4, name: "Antonio Ruiz", role: "Fallero de Honor", status: "Activo", email: "antonio.ruiz@example.com" },
    ];

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h2 className="text-3xl font-bold tracking-tight">Censo Fallero</h2>
                <button className="inline-flex items-center justify-center rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-4 py-2">
                    <UserPlus className="mr-2 h-4 w-4" />
                    Añadir Fallero
                </button>
            </div>

            <div className="rounded-md border bg-card text-card-foreground shadow">
                <div className="relative w-full overflow-auto">
                    <table className="w-full caption-bottom text-sm">
                        <thead className="[&_tr]:border-b">
                            <tr className="border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted">
                                <th className="h-12 px-4 text-left align-middle font-medium text-muted-foreground">Nombre</th>
                                <th className="h-12 px-4 text-left align-middle font-medium text-muted-foreground">Cargo</th>
                                <th className="h-12 px-4 text-left align-middle font-medium text-muted-foreground">Email</th>
                                <th className="h-12 px-4 text-left align-middle font-medium text-muted-foreground">Estado</th>
                                <th className="h-12 px-4 text-right align-middle font-medium text-muted-foreground">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="[&_tr:last-child]:border-0">
                            {members.map((member) => (
                                <tr key={member.id} className="border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted">
                                    <td className="p-4 align-middle font-medium">{member.name}</td>
                                    <td className="p-4 align-middle">{member.role}</td>
                                    <td className="p-4 align-middle">{member.email}</td>
                                    <td className="p-4 align-middle">
                                        <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-semibold ${member.status === "Activo" ? "bg-green-100 text-green-800" : "bg-yellow-100 text-yellow-800"
                                            }`}>
                                            {member.status}
                                        </span>
                                    </td>
                                    <td className="p-4 align-middle text-right">
                                        <button className="text-sm font-medium text-blue-600 hover:underline">Editar</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
